{
var imageA = inputs.Length > 0 ? inputs[0] : null;
        var imageB = inputs.Length > 1 ? inputs[1] : null;
        var maskInput = inputs.Length > 2 ? inputs[2] : null;
        var size = context.TileSize;

        if (imageA is null && imageB is null)
            return PixelBuffer.CreateSolid(size, size, 0, 0, 0);
        if (imageA is null)
            return imageB!.Clone();
        if (imageB is null)
            return imageA.Clone();

        var invertMask = GetBool(parameters, "invertMask");
        var hardness = GetFloat(parameters, "hardness", 1f);
        var maskContrast = GetFloat(parameters, "maskContrast", 0f);
        var maskOffset = GetFloat(parameters, "maskOffset", 0f);
        var defaultMix = GetFloat(parameters, "defaultMix", 0.5f);
        var maskChannel = GetChoice(parameters, "maskChannel", "luminance");

        // If no mask connected, blend using default ratio
        if (maskInput is null)
            return PixelBuffer.Lerp(imageA, imageB, defaultMix);

        var result = new PixelBuffer(size, size);

        result.ParallelForEachPixel((x, y) =>
        {
            float t;
            // Extract mask value from chosen channel
            var (mr, mg, mb, ma) = maskInput.GetPixelWrapped(x, y);
            switch (maskChannel)
            {
                case "redChannel": t = mr; break;
                case "greenChannel": t = mg; break;
                case "blueChannel": t = mb; break;
                case "alphaChannel": t = ma; break;
                default: t = 0.2126f * mr + 0.7152f * mg + 0.0722f * mb; break;
            }

            if (invertMask) t = 1f - t;

            // Apply mask contrast
            if (MathF.Abs(maskContrast) > 0.001f)
            {
                var contrastFactor = 1f + maskContrast;
                t = (t - 0.5f) * contrastFactor + 0.5f;
            }

            // Apply mask offset
            t += maskOffset;
            t = Math.Clamp(t, 0f, 1f);

            // Apply hardness: increase contrast of the mask edge
            if (hardness < 0.99f)
            {
                var mid = 0.5f;
                var range = (1f - hardness) * 0.5f;
                t = SmoothStep(mid - range, mid + range, t);
            }

            var (aR, aG, aB, aA) = imageA.GetPixelWrapped(x, y);
            var (bR, bG, bB, bA) = imageB.GetPixelWrapped(x, y);

            var r = Lerp(aR, bR, t);
            var g = Lerp(aG, bG, t);
            var b = Lerp(aB, bB, t);
            var a = Lerp(aA, bA, t);

            result.SetPixel(x, y, r, g, b, a);
        });

        return result;
}
